import type { WeaponType } from '../types';

export interface WeaponShot {
  x: number;
  y: number;
  vx: number;
  vy: number;
  damage: number;
  texture: string;
  radius: number;
}

export class WeaponSystem {
  private lastShotAt = 0;

  tryFire(nowMs: number, x: number, y: number, power: number, weapon: WeaponType): WeaponShot[] {
    if (weapon === 'plasma') {
      return [];
    }

    const cooldown = weapon === 'laser' ? 145 : 92;
    if (nowMs - this.lastShotAt < cooldown) {
      return [];
    }

    this.lastShotAt = nowMs;
    const level = Math.max(1, Math.min(6, power));
    if (weapon === 'laser') {
      return this.fireLaser(x, y, level);
    }

    return this.fireVulcan(x, y, level);
  }

  private fireVulcan(x: number, y: number, level: number): WeaponShot[] {
    const damage = 9 + level * 2;
    const shots: WeaponShot[] = [
      { x, y: y - 28, vx: 0, vy: -650, damage, texture: 'bullet-vulcan', radius: 5 },
    ];

    if (level >= 2) {
      shots.push({
        x: x - 15,
        y: y - 20,
        vx: -46,
        vy: -612,
        damage: damage * 0.75,
        texture: 'bullet-vulcan',
        radius: 5,
      });
      shots.push({
        x: x + 15,
        y: y - 20,
        vx: 46,
        vy: -612,
        damage: damage * 0.75,
        texture: 'bullet-vulcan',
        radius: 5,
      });
    }
    if (level >= 4) {
      shots.push({
        x: x - 30,
        y: y - 10,
        vx: -95,
        vy: -575,
        damage: damage * 0.6,
        texture: 'bullet-vulcan',
        radius: 5,
      });
      shots.push({
        x: x + 30,
        y: y - 10,
        vx: 95,
        vy: -575,
        damage: damage * 0.6,
        texture: 'bullet-vulcan',
        radius: 5,
      });
    }

    return shots;
  }

  private fireLaser(x: number, y: number, level: number): WeaponShot[] {
    const damage = 24 + level * 6;
    const shots: WeaponShot[] = [
      { x, y: y - 48, vx: 0, vy: -760, damage, texture: 'bullet-laser', radius: 7 },
    ];

    if (level >= 3) {
      shots.push({
        x: x - 18,
        y: y - 34,
        vx: -18,
        vy: -720,
        damage: damage * 0.6,
        texture: 'bullet-laser',
        radius: 6,
      });
      shots.push({
        x: x + 18,
        y: y - 34,
        vx: 18,
        vy: -720,
        damage: damage * 0.6,
        texture: 'bullet-laser',
        radius: 6,
      });
    }

    return shots;
  }

}
